import { createElement, Dot, Ellipsis, CirclePlus, X } from "lucide";
import { MainPanel } from '../components/MainPanel.js';
import { UserService } from "../../services/UserService";
import { LocalRepository } from "../../repository/LocalRepository";
import { format } from "date-fns";
import { StreakService } from "../../services/StreakService.js";
import { User } from "../../classes/User.js";

const displayTaskModal = (mode) => {
    const bg = document.createElement('div');
    const formContainer = document.createElement('div');
    const form = document.createElement('form');
    const formTitle = document.createElement('h1');
    const row1 = document.createElement('div');
    const row2 = document.createElement('div');
    const row3 = document.createElement('div');
    const row4 = document.createElement('div');
    const submit = document.createElement('button');
    const fieldSet = document.createElement('fieldset');
    const legend = document.createElement('legend');
    legend.textContent = "Priority: ";

    bg.className = "modal__overlay";
    formContainer.className = "formContainer";
    form.className = "taskForm";
    formTitle.className = "taskForm__title";


    // For row 1
    const titleLabel = document.createElement('label');
    const titleInput = document.createElement('input');
    titleLabel.textContent = "Title: ";
    titleLabel.setAttribute("for", "title");
    titleInput.id = "title";
    titleInput.name = "title";
    titleInput.type = "text";
    titleInput.required = true;
    row1.append(titleLabel, titleInput);


    // row 2
    const descLabel = document.createElement('label');
    const descInput = document.createElement('input');
    descLabel.textContent = "Description: ";
    descLabel.setAttribute("for", "description");
    descInput.id = "description";
    descInput.name = "description";
    descInput.type = "text";
    row2.append(descLabel, descInput);

    // row 3
    const dateLabel = document.createElement('label');
    const dateInput = document.createElement('input');
    dateLabel.textContent = "Date: ";
    dateLabel.setAttribute("for", "date");
    dateInput.id = "date";
    dateInput.name = "date";
    dateInput.type = "text";
    dateInput.required = true;
    row3.append(dateLabel, dateInput);


    // row 4
    fieldSet.appendChild(legend);
    const priorities = ["high", "mid", "low"];

    for (const prio of priorities) {
        const radioGroup = document.createElement('div');
        const prioLabel = document.createElement('label');
        const prioInput = document.createElement('input');
        prioLabel.textContent = `${prio[0].toUpperCase() + prio.slice(1)}`;
        prioLabel.setAttribute("for", prio);
        prioInput.id = prio;
        prioInput.name = "priority";
        prioInput.type = "radio";
        prioInput.value = prio;
        radioGroup.append(prioLabel, prioInput);
        fieldSet.append(radioGroup);
        row4.append(fieldSet);
        prioInput.required = true;
    }
    switch (mode) {
        case "create":
            submit.textContent = "Create";
            formTitle.textContent = "Create Task";
            break;
        case "edit":
            submit.textContent = "Edit";
            formTitle.textContent = "Edit Task";
            break;
    }

    form.append(formTitle, row1, row2, row3, row4, submit);
    formContainer.appendChild(form);
    bg.appendChild(formContainer);

    // Listeners

    bg.addEventListener('click', (e) => {
        if (e.target.closest(".modal__overlay")) {
            bg.remove();
        }
    })

    form.addEventListener('click', (e) => {
        e.stopPropagation();

        if (e.target.closest("input#date")) {
            dateInput.setAttribute("type", "date");
        } else {
            dateInput.setAttribute("type", "text");
        }
    })

    form.addEventListener('submit', (e) => {
        e.preventDefault();
        const formData = new FormData(form);
        const taskInfo = Array.from(formData.values());

        const list = document.querySelector('.tasksContainer__taskList');
        const user = UserService.loadLoggedInProfile(LocalRepository);

        let target = {};

        if (!list.dataset.origin) {
            target = user;
        } else {
            const projectId = list.dataset.origin.split('project-')[1];
            target = UserService.retrieveProject(projectId, user);
        }


        switch (mode) {
            case "create":
                const id = crypto.randomUUID();
                const newTask = UserService.createTaskForUser(target, [id, ...taskInfo]);
                UserService.assignTask(newTask, target);
                break;
            case "edit":
                const taskId = form.id
                const retrievedTask = UserService.retrieveTask(taskId, target)

                UserService.editTask(
                    retrievedTask,
                    {
                        title: taskInfo[0],
                        description: taskInfo[1],
                        dueDate: taskInfo[2],
                        priority: taskInfo[3]
                    },
                    target
                );
                break;
            default:
                break;
        }

        UserService.saveProfileToStorage(LocalRepository, user);
        Tasks.render(target);

        setTimeout(() => {
            bg.remove();
        }, 1000);

    });

    return bg;
}

const handleClick = (e) => {
    let taskModal = "";
    const taskItem = e.target.closest(".taskList__container");
    const taskBtn = e.target.closest(".task__btn");

    if (taskBtn) {
        taskModal = displayTaskModal("create");
        MainPanel.el.appendChild(taskModal);

        const titleInput = document.querySelector("input#title");
        const descInput = document.querySelector("input#description");
        const dateInput = document.querySelector("input#date");
        titleInput.placeholder = "Coding: To-Do App";
        descInput.placeholder = "Debugging line 43 col 23";
        dateInput.placeholder = format(Date.now(), "MM/dd/yyyy");
    }

    if (taskItem) {
        const list = document.querySelector('.tasksContainer__taskList');
        const edit = e.target.closest(".edit");
        const del = e.target.closest(".delete");
        const checkbox = e.target.closest("input[type='checkbox']");


        const user = UserService.loadLoggedInProfile(LocalRepository);
        let target = {};

        if (user.getTab() === "tasks") {
            target = user;
        } else {
            const projectId = list.dataset.origin.split('project-')[1];
            target = UserService.retrieveProject(projectId, user);
        }

        if (edit) {
            taskModal = displayTaskModal("edit");
            MainPanel.el.appendChild(taskModal);

            const id = taskItem.querySelector("input[type='checkbox']").id;
            const task = UserService.retrieveTask(id, target);

            const form = document.querySelector("form");
            const titleInput = document.querySelector("input#title");
            const descInput = document.querySelector("input#description");
            const dateInput = document.querySelector("input#date");
            const radioInput = document.querySelector(`input#${task.priority}`);


            titleInput.value = task.title;
            descInput.value = task.description;
            dateInput.value = task.dueDate;
            radioInput.checked = true;
            form.id = id;
            UserService.saveProfileToStorage(LocalRepository, user);
        }

        if (del) {
            const id = taskItem.querySelector("input[type='checkbox']").id;
            const task = UserService.retrieveTask(id, target);

            UserService.removeTask(task, target);
            UserService.saveProfileToStorage(LocalRepository, user);
            Tasks.render(target);
        }

        if (checkbox) {
            const id = checkbox.id;
            const targetTask = UserService.retrieveTask(id, target);

            if (e.currentTarget.className === 'completedTasksContainer__taskList' && targetTask.isDone === true) {
                UserService.undoComplete(targetTask, target, user);
                StreakService.undoLogActivity(user)
            } else {
                UserService.completeTask(targetTask, target, user);
                StreakService.logActivity(user);
            }

            UserService.saveProfileToStorage(LocalRepository, user);
            Tasks.render(target);
        }
    }

    return;
}

const createTaskList = (type) => {

    const header = document.createElement('header');
    const heading = document.createElement('h2');
    const taskCounter = document.createElement('span');
    const taskList = document.createElement('ul');

    switch (type) {
        case "normal":
            header.className = "taskHeader";
            heading.className = "tasksContainer__heading";
            taskCounter.className = "tasksContainer__taskCounter";
            taskList.className = "tasksContainer__taskList";
            heading.textContent = "Your Tasks";
            break;
        case "completed":
            header.className = "completedTaskHeader";
            heading.className = "completedTasksContainer__heading";
            taskCounter.className = "completedTasksContainer__taskCounter";
            taskList.className = "completedTasksContainer__taskList";
            heading.textContent = "Your Completed Tasks";
            break;
        default:
            console.error("Invalid type");
            return;
    }

    header.append(heading, taskCounter);

    return { header, taskCounter, taskList };
}


export const Tasks = (function () {
    const tasksDiv = document.createElement('div');
    const addTaskBtn = document.createElement('button');
    const plus = createElement(CirclePlus);


    tasksDiv.className = "tasksContainer";
    addTaskBtn.className = "task__btn";

    const normalTaskListObj = createTaskList("normal");
    const completedTaskListObj = createTaskList("completed");


    const prioMap = [
        ['low', 'green'],
        ['mid', 'blue'],
        ['high', 'red']
    ];


    const render = (taskHolder) => {
        const tasks = taskHolder.getTasks?.() ?? taskHolder.tasks;
        const tasksNodes = [];

        const completedTasks = taskHolder.getCompletedTasks?.() ?? taskHolder.completedTasks;
        const completedTasksNodes = [];

        tasks.forEach(task => {
            const del = createElement(X);
            const taskContainer = document.createElement('li');
            const taskItem = document.createElement('div');
            const leftSideOfItem = document.createElement('div');
            const rightSideOfItem = document.createElement('div');

            del.setAttribute('class', 'delete');
            taskContainer.className = "taskList__container";
            taskItem.className = "taskList__item";
            leftSideOfItem.className = "item__left";
            rightSideOfItem.className = "item__right";

            //left side elements
            const checkBox = document.createElement('input');
            checkBox.type = 'checkbox';
            checkBox.id = task.id;
            checkBox.name = 'user__task';
            const taskTitle = document.createElement('label');
            taskTitle.textContent = task.title;
            taskTitle.setAttribute("for", checkBox.id);

            //right side elements
            const dueDate = document.createElement('time');
            dueDate.textContent = format(task.dueDate, 'MMM do');

            const prio = createElement(Dot);
            const edit = createElement(Ellipsis);

            edit.classList.add("edit");


            for (const arr of prioMap) {
                if (arr[0] === task.priority) {
                    prio.style.setProperty('stroke', arr[1]);
                }
            }

            // append nodes to corresponding parents
            leftSideOfItem.append(checkBox, taskTitle);
            rightSideOfItem.append(dueDate, prio, edit);

            taskItem.append(leftSideOfItem, rightSideOfItem);
            taskContainer.append(taskItem, del);

            tasksNodes.push(taskContainer);
        });

        completedTasks.forEach(task => {
            const del = createElement(X);
            const taskContainer = document.createElement('li');
            const taskItem = document.createElement('div');
            const leftSideOfItem = document.createElement('div');
            const rightSideOfItem = document.createElement('div');

            del.setAttribute('class', 'delete');
            taskContainer.className = "taskList__container";
            taskItem.className = "taskList__item";
            leftSideOfItem.className = "item__left";
            rightSideOfItem.className = "item__right";

            //left side elements
            const checkBox = document.createElement('input');
            checkBox.type = 'checkbox';
            checkBox.id = task.id;
            checkBox.name = 'user__task';
            checkBox.checked = true;
            const taskTitle = document.createElement('label');
            taskTitle.textContent = task.title;
            taskTitle.setAttribute("for", checkBox.id);
            taskTitle.style.textDecoration = 'line-through';
            taskTitle.style.color = '#9D9D9D';

            //right side elements
            const dueDate = document.createElement('time');
            dueDate.textContent = format(task.dueDate, 'MMM do');

            const prio = createElement(Dot);
            const edit = createElement(Ellipsis);

            edit.classList.add("edit");


            for (const arr of prioMap) {
                if (arr[0] === task.priority) {
                    prio.style.setProperty('stroke', arr[1]);
                }
            }

            // append nodes to corresponding parents
            leftSideOfItem.append(checkBox, taskTitle);
            rightSideOfItem.append(dueDate, prio, edit);

            taskItem.append(leftSideOfItem, rightSideOfItem);
            taskContainer.append(taskItem, del);

            completedTasksNodes.push(taskContainer);
        });

        normalTaskListObj.taskList.replaceChildren(...tasksNodes);
        completedTaskListObj.taskList.replaceChildren(...completedTasksNodes);

        normalTaskListObj.taskList.appendChild(addTaskBtn);

        addTaskBtn.appendChild(plus);

        normalTaskListObj.taskCounter.textContent = tasks.length;
        completedTaskListObj.taskCounter.textContent = completedTasks.length;
    }

    const resetOrigin = () => {
        const list = document.querySelector('.tasksContainer__taskList');
        const completedList = document.querySelector('.completedTasksContainer__taskList');

        list.removeAttribute('data-origin');
        completedList.removeAttribute('data-origin');
    }

    normalTaskListObj.taskList.addEventListener('click', handleClick);
    completedTaskListObj.taskList.addEventListener('click', handleClick);


    tasksDiv.appendChild(normalTaskListObj.header);
    tasksDiv.appendChild(normalTaskListObj.taskList);
    tasksDiv.appendChild(completedTaskListObj.header);
    tasksDiv.appendChild(completedTaskListObj.taskList);


    return { el: tasksDiv, render, resetOrigin };
})();